import * as React from 'react';

import { cva, type VariantProps } from 'class-variance-authority';

import { ChevronDownIcon } from '../icons';
import { cn } from '../utils/cn';
import { Button } from './Button';

const disclosureTriggerVariants = cva(
  [
    'group/disclosure-trigger',
    'data-[state=open]:border-accent data-[state=open]:bg-btn-accent',
    // Darker hover when open.
    'data-[state=open]:hover:bg-brand-grey-300',
  ],
  {
    variants: {
      // Right-padding asymmetry to keep the indicator tighter to right side.
      size: {
        sm: 'gap-2 pr-1',
        md: 'gap-3 pr-1.5',
        lg: 'gap-4 pr-2',
      },
    },
    defaultVariants: {
      size: 'md',
    },
  }
);

type DisclosureTriggerProps = Omit<
  React.ComponentProps<typeof Button>,
  'variant' | 'color' | 'size'
> &
  VariantProps<typeof disclosureTriggerVariants>;

/**
 * Opinonated button design pattern for disclosure triggers (Popover, Dialog,
 * AlertDialog, Select, etc.).
 *
 * Styles based on `data-state` attribute set by Radix trigger components.
 * Displays a chevron indicator at right.
 */
function DisclosureTrigger({
  className,
  size = 'md',
  children,
  ...props
}: DisclosureTriggerProps) {
  const resolvedSize = size ?? 'md';
  return (
    <Button
      size={resolvedSize}
      className={cn(
        'flex-shrink',
        disclosureTriggerVariants({ size: resolvedSize }),
        className
      )}
      {...props}
    >
      <div
        data-testid="disclosure-trigger-content"
        className="flex-1 truncate text-left"
      >
        {children}
      </div>
      <DisclosureTriggerIndicator />
    </Button>
  );
}

type DisclosureTriggerIndicatorProps = React.ComponentProps<'span'>;

/**
 * Chevron indicator for disclosure triggers.
 *
 * Rotates 180° when the parent trigger's `data-state` is "open".
 * Must be used as a child of `DisclosureTrigger`.
 */
function DisclosureTriggerIndicator({
  className,
  ...props
}: DisclosureTriggerIndicatorProps) {
  return (
    <span
      data-testid="disclosure-trigger-indicator"
      className={cn(
        'inline-flex flex-shrink-0 transition-transform duration-200',
        'group-data-[state=open]/disclosure-trigger:rotate-180',
        className
      )}
      {...props}
    >
      <ChevronDownIcon />
    </span>
  );
}

export { DisclosureTrigger, DisclosureTriggerIndicator };
export type { DisclosureTriggerIndicatorProps, DisclosureTriggerProps };
